public void testStopWithUnknownLongOptionNoEquals() throws Exception
{
    String[] args = new String[]{"--unknown", "-a"};

    CommandLine cl = parser.parse(options, args, true);

    assertFalse("Confirm -a is not set", cl.hasOption("a"));
    assertTrue("Confirm 2 extra args: " + cl.getArgList().size(), cl.getArgList().size() == 2);
    assertEquals("First arg should be --unknown", "--unknown", cl.getArgList().get(0));
    assertEquals("Second arg should be -a", "-a", cl.getArgList().get(1));
}

public void testStopWithKnownLongOptionWithEquals() throws Exception
{
    options.addOption("zop", true, "zop option");
    String[] args = new String[]{"--zop=value", "-a"};

    CommandLine cl = parser.parse(options, args, true);

    assertTrue("Confirm --zop is set", cl.hasOption("zop"));
    assertEquals("Confirm --zop value", "value", cl.getOptionValue("zop"));
    assertFalse("Confirm -a is not set", cl.hasOption("a"));
    assertTrue("Confirm 1 extra arg: " + cl.getArgList().size(), cl.getArgList().size() == 1);
}

public void testStopWithMixedKnownUnknown() throws Exception
{
    options.addOption("x", true, "x option");
    String[] args = new String[]{"--x=1", "--unknown=2", "-a"};

    CommandLine cl = parser.parse(options, args, true);

    assertTrue("Confirm --x is set", cl.hasOption("x"));
    assertEquals("Confirm --x value", "1", cl.getOptionValue("x"));
    assertFalse("Confirm -a is not set", cl.hasOption("a"));
    assertTrue("Confirm 2 extra args: " + cl.getArgList().size(), cl.getArgList().size() == 2);
    assertEquals("First extra arg", "--unknown=2", cl.getArgList().get(0));
    assertEquals("Second extra arg", "-a", cl.getArgList().get(1));
}
